diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..722876d7b020 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3150,6 +3150,35 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
     }
   }

+  // select (select A, B, false), C, (select A, D, E) -> select A, (select B, C, D), E
+  // This pattern represents: if (A && B) C else (A ? D : E)
+  // which simplifies to: if (A) { if (B) C else D } else E
+  Value *OuterCond, *OuterTrue;
+  if (match(CondVal, m_Select(m_Value(OuterCond), m_Value(OuterTrue), m_Zero()))) {
+    if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+      if (FalseSI->getCondition() == OuterCond) {
+        // Create the inner select: select(OuterTrue, TrueVal, FalseSI->getTrueValue())
+        Value *InnerSel = Builder.CreateSelect(OuterTrue, TrueVal, FalseSI->getTrueValue());
+        // Return the outer select: select(OuterCond, InnerSel, FalseSI->getFalseValue())
+        return SelectInst::Create(OuterCond, InnerSel, FalseSI->getFalseValue());
+      }
+    }
+  }
+
+  // select (select A, true, B), (select A, D, E), C -> select A, D, (select B, E, C)
+  // This pattern represents: if (A || B) (A ? D : E) else C
+  // which simplifies to: if (A) D else (if (B) E else C)
+  Value *OuterFalse;
+  if (match(CondVal, m_Select(m_Value(OuterCond), m_One(), m_Value(OuterFalse)))) {
+    if (SelectInst *TrueSI = dyn_cast<SelectInst>(TrueVal)) {
+      if (TrueSI->getCondition() == OuterCond) {
+        // Create the inner select: select(OuterFalse, TrueSI->getFalseValue(), FalseVal)
+        Value *InnerSel = Builder.CreateSelect(OuterFalse, TrueSI->getFalseValue(), FalseVal);
+        // Return the outer select: select(OuterCond, TrueSI->getTrueValue(), InnerSel)
+        return SelectInst::Create(OuterCond, TrueSI->getTrueValue(), InnerSel);
+      }
+    }
+  }
